pub fn create_verifier_with_config<P>(
    config: VerificationConfig,
    executor_registry: std::sync::Arc<std::sync::RwLock<ExecutorRegistry>>,
    provider: P,
) -> VerificationResult<SpcVerifier<P>> {
    SpcVerifier::new(config, executor_registry, provider)
}

pub fn new(config: VerificationConfig, executor_registry: Arc<std::sync::RwLock<ExecutorRegistry>>, provider: P) -> VerificationResult<Self> {
    let client = VerificationClient::new(config.clone())?;
    Ok(Self { client, config, executor_registry, provider })
}
